INSERT INTO destinations (id, niche_id, name, country, description, currency, language, main_image_url, is_active) VALUES
('essaouira', 'wellness', 'Essaouira', 'Morocco', 'A windswept Atlantic gem where yoga retreats, ocean air, and artistic calm converge. Essaouira invites slow living — from medina-side meditation to beachfront breathwork, this coastal sanctuary is made for restoration.', 'EUR', 'French/Arabic', 'https://images.unsplash.com/photo-1569383746724-6f1b882b8f46?w=400', true),
('marrakech', 'wellness', 'Marrakech', 'Morocco', 'Beyond the bustle lies a city of luxury spas, palace-garden yoga, and centuries-old hammam rituals. Marrakech blends sensory richness with mindful exploration — the perfect place to recharge body, mind, and spirit.', 'EUR', 'French/Arabic', 'https://images.unsplash.com/photo-1597212618440-806262de4f6b?w=400', true),
('agadir', 'wellness', 'Agadir', 'Morocco', 'Sun-drenched beaches meet world-class thalassotherapy on Morocco''s southern coast. Agadir offers resort-style relaxation, surf therapy, and nature escapes — an effortless wellness retreat where the Atlantic does half the healing.', 'EUR', 'French/Arabic', 'https://images.unsplash.com/photo-1528909514045-2fa4ac7a08ba?w=400', true)
INSERT INTO activities (id, destination_id, title, description, duration, price, category, location, tags, main_image_url, is_active) VALUES
('ess-beach-yoga', 'essaouira', 'Beach Sunrise Yoga', 'Greet the day with a guided vinyasa flow on Essaouira''s wide sandy beach. The sound of Atlantic waves sets the rhythm as you stretch into the morning light.', 1.5, 25, 'Yoga & Meditation', 'Beach', ARRAY['yoga', 'beach', 'sunrise', 'morning'], 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=400', true),
('ess-rooftop-yoga', 'essaouira', 'Rooftop Yoga Session', 'Practice yoga on a whitewashed rooftop terrace overlooking the medina and ocean. A serene escape above the charming blue streets.', 1.5, 30, 'Yoga & Meditation', 'Medina rooftop', ARRAY['yoga', 'rooftop', 'morning', 'views'], 'https://images.unsplash.com/photo-1545389336-cf090694435e?w=400', true),
('ess-yoga-retreat', 'essaouira', 'Yoga Retreat Day', 'A full-day immersion with morning and afternoon yoga sessions, guided meditation, healthy lunch, and journaling time in a peaceful riad setting.', 7, 65, 'Yoga & Meditation', 'Riad retreat center', ARRAY['yoga', 'retreat', 'full-day', 'meditation'], 'https://images.unsplash.com/photo-1599901860904-17e6ed7083a0?w=400', true),
('ess-hammam', 'essaouira', 'Traditional Hammam Ritual', 'Experience an authentic Moroccan hammam with black soap scrub, rhassoul clay mask, and eucalyptus steam. A centuries-old purification ritual.', 2, 50, 'Spa & Hammam', 'Medina', ARRAY['hammam', 'spa', 'traditional', 'afternoon'], 'https://images.unsplash.com/photo-1544161515-4ab6ce6db874?w=400', true),
('ess-argan-massage', 'essaouira', 'Argan Oil Massage', 'Deep relaxation massage using locally pressed argan oil. Melt away tension in a candlelit treatment room with soft Gnawa music.', 1.5, 45, 'Spa & Hammam', 'Spa', ARRAY['massage', 'argan', 'relaxation', 'afternoon'], 'https://images.unsplash.com/photo-1600334089648-b0d9d3028eb2?w=400', true),
('ess-thalasso', 'essaouira', 'Thalassotherapy Session', 'Harness the healing power of the Atlantic with a seawater therapy session. Includes hydrotherapy pool, algae wrap, and mineral-rich body treatment.', 2.5, 70, 'Spa & Hammam', 'Coastal spa', ARRAY['thalasso', 'spa', 'ocean', 'afternoon'], 'https://images.unsplash.com/photo-1540555700478-4be289fbec6d?w=400', true),
('ess-surf', 'essaouira', 'Surf Therapy Session', 'Combine the thrill of surfing with mindful presence. A certified instructor guides you through waves and breathing techniques — therapy on a board.', 2.5, 50, 'Active Wellness', 'Beach', ARRAY['surf', 'therapy', 'active', 'morning'], 'https://images.unsplash.com/photo-1502680390548-bdbac40e2009?w=400', true),
('ess-walking-med', 'essaouira', 'Beach Walking Meditation', 'A slow, guided walking meditation along the shoreline. Focus on breath, waves, and the feeling of sand underfoot — simple yet deeply grounding.', 1, 20, 'Nature & Mindfulness', 'Beach', ARRAY['meditation', 'beach', 'walking', 'morning'], 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400', true),
('ess-coastal-hike', 'essaouira', 'Coastal Hike to Sidi Kaouki', 'A scenic coastal walk to the peaceful village of Sidi Kaouki. Breathe in the ocean air, spot wildlife, and enjoy tea upon arrival.', 4, 30, 'Active Wellness', 'Coast south of Essaouira', ARRAY['hike', 'coastal', 'nature', 'morning'], 'https://images.unsplash.com/photo-1551632811-561732d1e306?w=400', true),
('ess-cooking', 'essaouira', 'Healthy Cooking Class', 'Learn to prepare nourishing Moroccan dishes with a wellness twist — vegetable tajines, grain bowls, and herbal infusions using local market ingredients.', 3, 45, 'Healthy Eating', 'Riad kitchen', ARRAY['cooking', 'healthy', 'moroccan', 'afternoon'], 'https://images.unsplash.com/photo-1556910103-1c02745aae4d?w=400', true),
('ess-market-smoothie', 'essaouira', 'Organic Market Tour & Smoothie Workshop', 'Explore Essaouira''s vibrant market stalls for fresh produce, then blend your own superfood smoothies using argan, dates, almonds, and seasonal fruits.', 2.5, 35, 'Healthy Eating', 'Market & riad', ARRAY['market', 'smoothie', 'organic', 'morning'], 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?w=400', true),
('ess-art-therapy', 'essaouira', 'Art Therapy in the Medina', 'Express yourself through painting and collage in a medina art studio. Guided by a therapist-artist, this session blends creativity with emotional release.', 2.5, 40, 'Creative Therapy', 'Medina gallery', ARRAY['art', 'therapy', 'creative', 'afternoon'], 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?w=400', true),
('ess-pottery', 'essaouira', 'Pottery Workshop', 'Shape clay on a traditional wheel in a peaceful studio. A meditative craft that grounds the mind and awakens tactile creativity.', 2, 35, 'Creative Therapy', 'Artisan workshop', ARRAY['pottery', 'craft', 'meditation', 'afternoon'], 'https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=400', true)
INSERT INTO activities (id, destination_id, title, description, duration, price, category, location, tags, main_image_url, is_active) VALUES
('mkch-royal-hammam', 'marrakech', 'Royal Hammam Experience', 'An elevated hammam ritual in a restored palace bathhouse. Black soap, ghassoul clay, rose water rinse, and argan oil massage — fit for royalty.', 2.5, 75, 'Spa & Hammam', 'Medina palace', ARRAY['hammam', 'luxury', 'spa', 'afternoon'], 'https://images.unsplash.com/photo-1544161515-4ab6ce6db874?w=400', true),
('mkch-luxury-spa', 'marrakech', 'Luxury Spa Half-Day', 'Indulge in a half-day spa journey: hammam, full-body massage, facial, and mint tea by the pool. Pure Marrakech opulence.', 4, 95, 'Spa & Hammam', 'Hivernage spa hotel', ARRAY['spa', 'luxury', 'half-day', 'afternoon'], 'https://images.unsplash.com/photo-1600334089648-b0d9d3028eb2?w=400', true),
('mkch-argan-beauty', 'marrakech', 'Argan Oil Beauty Ritual', 'A beauty-focused treatment using pure argan oil: scalp massage, hair treatment, facial, and hand care. Leave glowing from head to toe.', 2, 55, 'Spa & Hammam', 'Guéliz spa', ARRAY['argan', 'beauty', 'facial', 'afternoon'], 'https://images.unsplash.com/photo-1570172619644-dfd03ed5d881?w=400', true),
('mkch-garden-yoga', 'marrakech', 'Garden Yoga in a Palace', 'Practice yoga surrounded by orange trees, fountains, and intricate zellige tilework in a private palace garden. A uniquely Moroccan flow.', 1.5, 35, 'Yoga & Meditation', 'Palace garden', ARRAY['yoga', 'garden', 'palace', 'morning'], 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=400', true),
('mkch-rooftop-med', 'marrakech', 'Sunrise Rooftop Meditation', 'Watch the sun rise over the Atlas Mountains from a riad rooftop while guided through breathwork and silent meditation.', 1, 25, 'Yoga & Meditation', 'Medina rooftop', ARRAY['meditation', 'sunrise', 'rooftop', 'morning'], 'https://images.unsplash.com/photo-1545389336-cf090694435e?w=400', true),
('mkch-sound-heal', 'marrakech', 'Sound Healing Session', 'Lie back as Tibetan singing bowls, crystal bowls, and gentle percussion wash over you. A vibrational therapy session that dissolves tension.', 1.5, 40, 'Yoga & Meditation', 'Wellness riad', ARRAY['sound', 'healing', 'meditation', 'afternoon'], 'https://images.unsplash.com/photo-1591291621164-2c6367723315?w=400', true),
('mkch-palm-cycle', 'marrakech', 'Palm Grove Cycling', 'A gentle morning bike ride through the Palmeraie palm groves. Fresh air, birdsong, and a refreshing stop at a garden café.', 2, 30, 'Active Wellness', 'Palmeraie', ARRAY['cycling', 'nature', 'active', 'morning'], 'https://images.unsplash.com/photo-1541625602330-2277a4c46182?w=400', true),
('mkch-atlas-hike', 'marrakech', 'Atlas Mountain Gentle Hike', 'A moderate hike through the foothills of the Atlas Mountains. Berber villages, valley views, and a herbal tea stop in a mountain home.', 5, 50, 'Active Wellness', 'Atlas foothills', ARRAY['hike', 'mountains', 'nature', 'morning'], 'https://images.unsplash.com/photo-1551632811-561732d1e306?w=400', true),
('mkch-plant-cook', 'marrakech', 'Plant-Based Cooking Class', 'Master vibrant Moroccan plant-based dishes: harira soup, vegetable tajine, chickpea salads, and orange-blossom desserts in a riad kitchen.', 3, 50, 'Healthy Eating', 'Riad kitchen', ARRAY['cooking', 'plant-based', 'vegan', 'afternoon'], 'https://images.unsplash.com/photo-1556910103-1c02745aae4d?w=400', true),
('mkch-tea-blend', 'marrakech', 'Herbal Tea Blending Workshop', 'Learn the art of Moroccan herbal blends — mint, verbena, saffron, rose. Discover the therapeutic properties and take your blends home.', 1.5, 30, 'Healthy Eating', 'Medina herb shop', ARRAY['tea', 'herbal', 'workshop', 'afternoon'], 'https://images.unsplash.com/photo-1564890369478-c89ca6d9cde9?w=400', true),
('mkch-farm-lunch', 'marrakech', 'Farm-to-Table Lunch', 'Dine at an organic farm outside Marrakech. Harvest vegetables, then enjoy a freshly prepared multi-course lunch with Atlas views.', 4, 45, 'Healthy Eating', 'Countryside farm', ARRAY['farm', 'organic', 'lunch', 'afternoon'], 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=400', true),
('mkch-majorelle', 'marrakech', 'Majorelle Garden Mindful Walk', 'A guided mindfulness walk through the iconic Majorelle Garden. Slow down among cobalt-blue structures, bamboo groves, and lotus pools.', 2, 35, 'Nature & Mindfulness', 'Guéliz', ARRAY['garden', 'mindfulness', 'walking', 'morning'], 'https://images.unsplash.com/photo-1569383746724-6f1b882b8f46?w=400', true),
('mkch-calligraphy', 'marrakech', 'Calligraphy Meditation', 'Learn Arabic calligraphy as a meditative practice. The rhythmic brush strokes quiet the mind while creating beautiful art to take home.', 2, 40, 'Creative Therapy', 'Medina studio', ARRAY['calligraphy', 'art', 'meditation', 'afternoon'], 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?w=400', true)
INSERT INTO activities (id, destination_id, title, description, duration, price, category, location, tags, main_image_url, is_active) VALUES
('agd-thalasso', 'agadir', 'Thalassotherapy Center Day', 'A full day at Agadir''s premier thalassotherapy center. Seawater pool, jet showers, algae body wrap, and relaxation lounge with ocean views.', 6, 80, 'Spa & Hammam', 'Beachfront thalasso center', ARRAY['thalasso', 'spa', 'full-day', 'afternoon'], 'https://images.unsplash.com/photo-1540555700478-4be289fbec6d?w=400', true),
('agd-beach-massage', 'agadir', 'Beach Massage', 'Unwind with a relaxing massage on the golden sands of Agadir beach. The sound of waves and warm ocean breeze complete the experience.', 1, 40, 'Spa & Hammam', 'Beach', ARRAY['massage', 'beach', 'relaxation', 'afternoon'], 'https://images.unsplash.com/photo-1600334089648-b0d9d3028eb2?w=400', true),
('agd-hammam', 'agadir', 'Hammam & Gommage', 'Traditional steam bath followed by a vigorous exfoliation with kessa glove and black soap. Emerge with silky smooth skin and total relaxation.', 2, 50, 'Spa & Hammam', 'City center hammam', ARRAY['hammam', 'gommage', 'spa', 'afternoon'], 'https://images.unsplash.com/photo-1544161515-4ab6ce6db874?w=400', true),
('agd-morning-yoga', 'agadir', 'Morning Beach Yoga', 'Start your day with a gentle yoga class on Agadir''s long sandy beach. Sun salutations facing the Atlantic — the perfect morning ritual.', 1.5, 20, 'Yoga & Meditation', 'Beach', ARRAY['yoga', 'beach', 'morning', 'sunrise'], 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=400', true),
('agd-surf', 'agadir', 'Surf Lesson', 'Ride the Atlantic waves with a professional surf instructor. All equipment provided. Suitable for beginners and intermediate surfers.', 2, 45, 'Active Wellness', 'Taghazout area', ARRAY['surf', 'active', 'beach', 'morning'], 'https://images.unsplash.com/photo-1502680390548-bdbac40e2009?w=400', true),
('agd-sup', 'agadir', 'Stand-Up Paddleboard', 'Glide across calm morning waters on a paddleboard. A peaceful full-body workout with views of Agadir''s coastline and the Kasbah hill.', 1.5, 30, 'Active Wellness', 'Marina', ARRAY['sup', 'paddleboard', 'active', 'morning'], 'https://images.unsplash.com/photo-1526188717906-ab4a2f949f23?w=400', true),
('agd-coastal-walk', 'agadir', 'Coastal Nature Walk', 'A leisurely guided walk along the Agadir corniche and coastal paths. Breathe in the sea air, spot seabirds, and enjoy panoramic ocean views.', 1.5, 15, 'Nature & Mindfulness', 'Corniche', ARRAY['walking', 'nature', 'coastal', 'morning'], 'https://images.unsplash.com/photo-1507525428034-b723cf090694435e?w=400', true),
('agd-seafood-detox', 'agadir', 'Fresh Seafood Detox Lunch', 'A light, nourishing seafood lunch at the port — grilled fish, citrus salads, and fresh juices. Clean eating with an ocean view.', 2, 30, 'Healthy Eating', 'Port area', ARRAY['seafood', 'healthy', 'lunch', 'afternoon'], 'https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=400', true),
('agd-juice-bar', 'agadir', 'Juice Bar Workshop', 'Blend tropical fruits, local herbs, and superfoods into revitalizing juices and smoothie bowls. Learn recipes to recreate at home.', 1.5, 25, 'Healthy Eating', 'City center café', ARRAY['juice', 'smoothie', 'workshop', 'morning'], 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?w=400', true),
('agd-souss-massa', 'agadir', 'Souss-Massa Nature Reserve Visit', 'Explore Morocco''s stunning coastal nature reserve. Spot flamingos, ibis, and rare bald ibis while walking through dunes and river estuaries.', 4, 35, 'Nature & Mindfulness', 'Souss-Massa National Park', ARRAY['nature', 'reserve', 'birdwatching', 'morning'], 'https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=400', true),
('agd-argan-forest', 'agadir', 'Argan Forest Walk', 'Walk through the UNESCO-protected argan forest. Learn about the tree''s ecological importance, meet local cooperatives, and taste fresh argan oil.', 3, 25, 'Nature & Mindfulness', 'Argan forest', ARRAY['argan', 'forest', 'nature', 'morning'], 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=400', true)
INSERT INTO accommodations (id, destination_id, name, type, description, location, price_per_night, rating, amenities, main_image_url, is_active) VALUES
('ess-yoga-riad', 'essaouira', 'Riad Yoga Retreat', 'Riad', 'A serene medina riad dedicated to yoga guests. Rooftop practice space, healthy breakfast, and a tranquil courtyard with fountain.', 'Medina', 75, 4, ARRAY['wifi', 'yoga-terrace', 'healthy-breakfast', 'courtyard', 'rooftop'], 'https://images.unsplash.com/photo-1548018560-c7196548e84d?w=400', true),
('ess-eco-lodge', 'essaouira', 'Atlantic Eco-Lodge', 'Eco-Lodge', 'Sustainable beachside lodge with organic linens, solar power, and farm-to-table meals. Steps from the sand.', 'Beach road', 95, 4, ARRAY['wifi', 'eco-friendly', 'organic-meals', 'beach-access', 'garden'], 'https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=400', true),
('ess-spa-hotel', 'essaouira', 'Essaouira Spa Hotel', 'Hotel', 'Modern hotel with on-site spa, hammam, ocean-view pool, and wellness-focused restaurant. Ideal for a comfortable retreat.', 'Beachfront', 120, 4, ARRAY['wifi', 'spa', 'hammam', 'pool', 'restaurant', 'ocean-view'], 'https://images.unsplash.com/photo-1571003123894-1f0594d2b5d9?w=400', true),
('ess-garden-riad', 'essaouira', 'Riad Jardin Bleu', 'Riad', 'Charming blue-and-white riad with lush garden patio, plunge pool, and quiet reading nooks. A peaceful medina hideaway.', 'Medina', 65, 3, ARRAY['wifi', 'garden', 'plunge-pool', 'breakfast-included', 'library'], 'https://images.unsplash.com/photo-1548018560-c7196548e84d?w=400', true),
('ess-boutique', 'essaouira', 'Dar Sérénité Boutique', 'Boutique Hotel', 'Intimate boutique hotel with just eight rooms, each designed for calm. Rooftop sunset terrace and daily herbal tea service.', 'Medina', 85, 4, ARRAY['wifi', 'rooftop-terrace', 'herbal-tea', 'breakfast-included', 'air-conditioning'], 'https://images.unsplash.com/photo-1566073771259-6a8506099945?w=400', true),
('ess-budget', 'essaouira', 'Maison du Vent', 'Guesthouse', 'A welcoming budget guesthouse with clean rooms, shared yoga space, and communal kitchen. Great for solo travelers.', 'Medina', 40, 3, ARRAY['wifi', 'shared-yoga-space', 'communal-kitchen', 'breakfast-available'], 'https://images.unsplash.com/photo-1564501049412-61c2a3083791?w=400', true)
INSERT INTO accommodations (id, destination_id, name, type, description, location, price_per_night, rating, amenities, main_image_url, is_active) VALUES
('mkch-palace-riad', 'marrakech', 'Riad Palace Retreat', 'Riad', 'A restored palace riad with private hammam, garden courtyard, and rooftop yoga deck. Luxury meets tradition in the heart of the medina.', 'Medina', 160, 5, ARRAY['wifi', 'hammam', 'yoga-deck', 'garden', 'concierge', 'breakfast-included'], 'https://images.unsplash.com/photo-1548018560-c7196548e84d?w=400', true),
