('mkch-budget', 'marrakech', 'Dar Calme Guesthouse', 'Guesthouse', 'Affordable medina guesthouse with rooftop terrace, simple healthy breakfast, and a peaceful atmosphere away from the crowds.', 'Medina', 50, 3, ARRAY['wifi', 'rooftop-terrace', 'breakfast-included', 'air-conditioning'], 'https://images.unsplash.com/photo-1564501049412-61c2a3083791?w=400', true)
INSERT INTO accommodations (id, destination_id, name, type, description, location, price_per_night, rating, amenities, main_image_url, is_active) VALUES
('agd-thalasso-hotel', 'agadir', 'Atlantic Thalasso Hotel', 'Hotel', 'Beachfront hotel with in-house thalassotherapy center, infinity pool, and panoramic ocean-view spa. The ultimate coastal wellness base.', 'Beachfront', 140, 5, ARRAY['wifi', 'thalasso-center', 'pool', 'spa', 'ocean-view', 'restaurant'], 'https://images.unsplash.com/photo-1571003123894-1f0594d2b5d9?w=400', true),
