('agd-beach-resort', 'agadir', 'Sofitel Agadir Wellness', 'Resort', 'Five-star beach resort with world-class spa, heated pools, fitness center, and multiple dining options including a health-focused bistro.', 'Beachfront', 155, 5, ARRAY['wifi', 'spa', 'pools', 'gym', 'restaurants', 'beach-access', 'concierge'], 'https://images.unsplash.com/photo-1566073771259-6a8506099945?w=400', true),
('agd-eco-riad', 'agadir', 'Riad Nature Agadir', 'Riad', 'An eco-conscious riad with garden, organic breakfast, and a calm rooftop with mountain views. A green oasis in the city.', 'City center', 65, 3, ARRAY['wifi', 'garden', 'organic-breakfast', 'rooftop', 'eco-friendly'], 'https://images.unsplash.com/photo-1548018560-c7196548e84d?w=400', true),
('agd-apart-hotel', 'agadir', 'Marina Wellness Aparthotel', 'Aparthotel', 'Self-catering apartments near the marina with kitchenette, pool access, and proximity to the beach. Great for longer stays.', 'Marina', 55, 3, ARRAY['wifi', 'kitchenette', 'pool', 'laundry', 'parking'], 'https://images.unsplash.com/photo-1564501049412-61c2a3083791?w=400', true),
('agd-budget', 'agadir', 'Kasbah View Guesthouse', 'Guesthouse', 'Friendly budget guesthouse with clean rooms, breakfast terrace, and views of the hilltop Kasbah. Excellent value.', 'Talborjt', 42, 3, ARRAY['wifi', 'breakfast-terrace', 'air-conditioning', 'city-views'], 'https://images.unsplash.com/photo-1564501049412-61c2a3083791?w=400', true)
